#else
#include "loongarch.h"
#endif

void init_process();

extern void kernelvec();

#if defined RISCV
extern void virtio_disk_init();
#else
extern void virtio_probe();
extern void la_virtio_disk_init(); 
#endif

int yungekc_start_kernel()
{
#if defined RISCV
    extern void kernelvec();
    w_stvec((uint64)kernelvec);
#endif
    chardev_init();
    printfinit();
    for (int i = 65; i < 65 + 26; i++)
    {
        put_char_sync(i);
        put_char_sync('t');
    }
    put_char_sync('\n');
    printf_figlet_color("yungekc Is Booting!"); //< 艺术字打印
    LOG("yungekc_start_kernel at :%p\n", &yungekc_start_kernel);
    extern uint64 boot_time;
    LOG("System boot timestamp is: %lld\n", boot_time);
    // 初始化线程和进程
    thread_init();
    proc_init();
    // 初始化物理内存
    pmem_init();
    vmem_init();
    slab_init();
    hsai_trap_init();
    // 初始化磁盘设备。本来想把这个提取到hsai的，但是发现那么做会使la运行速度变慢，先这样
#if defined RISCV
    virtio_disk_init();
    plicinit();
    plicinithart();
#else 
    virtio_probe();//发现virtio-blk-pci设备
    la_virtio_disk_init();
#endif
    // 初始化文件系统
    init_fs();
    binit();
    fileinit();
    inodeinit();
    vfs_ext4_init();
    init_process();
    // 进入调度器
    scheduler();
    while (1)
        return 0;
}

#if defined RISCV
#include "rv_init_code.h" //< unsigned char initcode[]
#else
#include "la_init_code.h" //< unsigned char initcode[]

#endif
/**
 * @brief 初始化init线程，进入scheduler后调度执行
 */
extern proc_t *initproc;
void init_process()
{
    struct proc *p = allocproc();
    initproc = p;
    p->state = RUNNABLE;
    uint32 len = sizeof(init_code);
    printf("user len:%p\n", len);
    LOG("user init_code: %p\n", init_code);
    printf("[DBG] before uvminit\n");
    uvminit(p, init_code, len);
    printf("[DBG] after uvminit\n");
    p->virt_addr = 0;
    p->sz = len;
    p->sz = PGROUNDUP(p->sz);
    p->cwd.fs = get_fs_by_type(EXT4);
    uint64 sp =  get_proc_sp(p);
    strcpy(p->cwd.path, "/");
    hsai_set_trapframe_epc(p->trapframe, 0);
    hsai_set_trapframe_user_sp(p->trapframe, sp);
    copytrapframe(p->main_thread->trapframe, p->trapframe);
    p->main_thread->state = t_RUNNABLE; ///< 设置主线程状态为可运行
    printf("[DBG] init_process done\n");
    release(&p->lock); ///< 释放在allocproc()中加的锁
}

