// 控制打印锁启用的全局变量
int pr_locking_enable = 0;

int main()
{
    while (1)
        ;
} // 为了通过编译, never use this

void init_process();
void service_process_init();

#if defined RISCV
extern void virtio_disk_init();
#else
extern void virtio_probe();
extern void la_virtio_disk_init();
#endif

volatile static int started = 0;
volatile int hart0_is_starting = 0;
volatile int first_hart = 0; // 以防启动不完全

int sc7_start_kernel()
{
    hsai_hart_disorder_boot();

    if (hsai_get_cpuid() == 0)
    {
        hart0_is_starting = 1;
        // 初始化输出串口
        chardev_init();
        printfinit();
        printf_figlet_color("SC7 Is Booting!"); //< 艺术字打印
        LOG("sc7_start_kernel at :%p\n", &sc7_start_kernel);
        extern uint64 boot_time;
        LOG("System boot timestamp is: %lld\n", boot_time);
        // 初始化线程和进程
        thread_init();
        proc_init();
        // 初始化物理内存
        pmem_init();
        vmem_init();
        shm_init();
        slab_init();
        // 初始化中断和异常
        hsai_trap_init();
        // 初始化磁盘设备。本来想把这个提取到hsai的，但是发现那么做会使la运行速度变慢，先这样
#if defined RISCV
        plicinit();
        plicinithart();
        virtio_disk_init();
#else
        virtio_probe(); // 发现virtio-blk-pci设备
        la_virtio_disk_init();
#endif
        // 初始化文件系统
        init_fs();
        binit();
        fileinit();
        inodeinit();
        vfs_ext4_init();
        // 初始化init线程
        service_process_init();
        init_process();
        __sync_synchronize();
        printf("hart %d starting\n", hsai_get_cpuid());

        // 在唤醒其他核之前启用打印锁
        pr_locking_enable = 1; // 暂时注释掉，避免启动时的锁竞争
        enable_print_lock();   // 暂时注释掉，避免启动时的锁竞争
        __sync_synchronize();

        started = 1;

        hsai_hart_start_all();
    }
    else // 其它核心初始化自己
    {
        while (started == 0)
            ;
        __sync_synchronize();

        // 额外等待，确保核0完全启动完成
        while (pr_locking_enable == 0)
            ;
        __sync_synchronize();

        printf("hart %d starting\n", hsai_get_cpuid());
        kvm_init_hart();
        hsai_trap_init();
#if defined RISCV
        plicinithart();
#endif
    }
    // 进入调度器

    scheduler();
}

