    printf("eentry: %p\n", r_csr_eentry());
    printf("pgdl: %p\n", r_csr_pgdl());
    printf("estatus: %p\n", r_csr_estat());
    printf("sp: %p\n", r_sp());
    printf("tp: %p\n", r_tp());
    printf("}\n");
#endif
}

// initialize the proc table at boot time.
void proc_init(void)
{
    struct proc *p;
    initlock(&pid_lock, "nextpid");
    initlock(&parent_lock, "parent_lock");

    /* 初始化UTS命名空间系统 */
    init_uts_namespaces();

    for (p = pool; p < &pool[NPROC]; p++)
    {
        initlock(&p->lock, "proc");
        p->state = UNUSED;
        p->exit_state = 0;
        p->kstack = KSTACK((int)(p - pool));
        // p->trapframe = (struct trapframe *)trapframe[p - pool];
        p->trapframe = 0;
        p->parent = 0;
        p->ktime = 0;
        p->utime = 0;
        // 初始化文件描述符数组
        for (int i = 0; i < NOFILE; i++)
            p->ofile[i] = 0;
    }
}

int allocpid(void)
{
    static int PID = 1;
    acquire(&pid_lock);
    int pid = PID++;
    release(&pid_lock);
    if (pid > PID_MAX)
    {
        return -1;
    }
    return pid;
}

struct proc *getproc(int pid)
{
    struct proc *p;
    for (p = pool; p < &pool[NPROC]; p++)
    {
        if (p->pid == pid)
        {
            return p;
        }
    }
    return NULL;
}

static void
copycontext(context_t *t1, context_t *t2)
{
#ifdef RISCV
    t1->ra = t2->ra;
    t1->sp = t2->sp;
    t1->s0 = t2->s0;
    t1->s1 = t2->s1;
    t1->s2 = t2->s2;
    t1->s3 = t2->s3;
    t1->s4 = t2->s4;
    t1->s5 = t2->s5;
    t1->s6 = t2->s6;
    t1->s7 = t2->s7;
    t1->s8 = t2->s8;
    t1->s9 = t2->s9;
    t1->s10 = t2->s10;
    t1->s11 = t2->s11;
#else
    t1->ra = t2->ra;
    t1->sp = t2->sp;
    t1->s0 = t2->s0;
    t1->s1 = t2->s1;
    t1->s2 = t2->s2;
    t1->s3 = t2->s3;
    t1->s4 = t2->s4;
    t1->s5 = t2->s5;
    t1->s6 = t2->s6;
    t1->s7 = t2->s7;
    t1->s8 = t2->s8;
    t1->fp = t2->fp;
#endif
}

// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel.
// If there are no free procs, or a memory allocation fails, return 0.
struct proc *allocproc(void)
{
    struct proc *p;
    for (p = pool; p < &pool[NPROC]; p++)
    {
        acquire(&p->lock);
        if (p->state == UNUSED)
        {
            goto found;
        }
        else
            release(&p->lock);
    }
    return 0;

found:
    p->ktime = 1;
    p->utime = 1;
    p->pid = allocpid();
    if (p->pid < 0)
    {
        return NULL;
    }
    p->ruid = 0;                                                         // Real User ID
    p->euid = 0;                                                         // Effective User ID
    p->suid = 0;                                                         // Saved User ID
    p->rgid = 0;                                                         // Real Group ID
    p->egid = 0;                                                         // Effective Group ID
    p->sgid = 0;                                                         // Saved Group ID
    p->umask = 0022;                                                     // 默认umask为0022 (rw-r--r--)
    p->pgid = p->pid;                                                    // 默认进程组ID等于进程ID
    p->sid = p->pid;                                                     // 默认会话ID等于进程ID
    p->ngroups = 0;                                                      // 初始化补充组ID数量为0
    memset(p->supplementary_groups, 0, sizeof(p->supplementary_groups)); // 清空补充组ID数组
    p->thread_num = 0;
    p->state = USED;
    p->exit_state = 0;
    p->vma = NULL;
    p->killed = 0;
    p->clear_child_tid = 0;
    p->ofn = (struct rlimit){NOFILE, NOFILE};
    // 初始化文件描述符数组
    for (int i = 0; i < NOFILE; i++)
        p->ofile[i] = 0;

    // 初始化资源限制数组
    // 设置默认的资源限制值
    p->rlimits[RLIMIT_CPU] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_FSIZE] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_DATA] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_STACK] = (struct rlimit){8 * 1024 * 1024, RLIM_INFINITY}; // 8MB 默认栈大小
    p->rlimits[RLIMIT_CORE] = (struct rlimit){0, RLIM_INFINITY};                // 默认不生成core文件
    p->rlimits[RLIMIT_RSS] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_NPROC] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_NOFILE] = (struct rlimit){NOFILE, NOFILE};
    p->rlimits[RLIMIT_MEMLOCK] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_AS] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_LOCKS] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
