    p->rlimits[RLIMIT_MSGQUEUE] = (struct rlimit){RLIM_INFINITY, RLIM_INFINITY};
    p->rlimits[RLIMIT_NICE] = (struct rlimit){0, 0};   // 默认优先级
    p->rlimits[RLIMIT_RTPRIO] = (struct rlimit){0, 0}; // 默认实时优先级
