            base[4 + i] = (uint32)(mem_addr);
            base[4 + i + 1] = (uint32)(mem_addr >> 32);
            __sync_synchronize();
            printf("%p\n", mem_addr);
            i++; // 跳过下一个 BAR
        }
    }
