{
    if (prth_i)
    {
        prth_i->valid = false;
    }
}

// 初始化中断计数器
void init_interrupt_counts(void)
{
    initlock(&interrupt_lock, "interrupt_counts");
    for (int i = 0; i < 256; i++)
    {
        interrupt_counts[i] = 0;
    }
}

// 增加中断计数
void increment_interrupt_count(int irq)
{
    if (irq >= 0 && irq < 256)
    {
        acquire(&interrupt_lock);
        interrupt_counts[irq]++;
        release(&interrupt_lock);
    }
}

