OUTPUT_ARCH( "riscv" )
ENTRY( _entry )

SECTIONS
{
  /*
   * ensure that entry.S / _entry is at 0x80000000,
   * where qemu's -kernel jumps.
   */
  . = 0x80000000;

  .text : {
    *(.text .text.*)
    . = ALIGN(0x1000);
    _trampoline = .;
    *(.text.trampoline)  # 改为匹配.text.trampoline段
    . = ALIGN(0x1000);
    ASSERT(. - _trampoline <= 0x1000, "error: trampoline larger than one page");
    PROVIDE(KERNEL_TEXT = .);
}

  .rodata : {
    . = ALIGN(16);
    *(.srodata .srodata.*) /* do not need to distinguish this from .rodata */
    . = ALIGN(16);
    *(.rodata .rodata.*)
  }

  .data : {
    . = ALIGN(16);
    *(.sdata .sdata.*) /* do not need to distinguish this from .data */
    . = ALIGN(16);
    *(.data .data.*)
  }

  .bss : {
    . = ALIGN(16);
    *(.sbss .sbss.*) /* do not need to distinguish this from .bss */
    . = ALIGN(16);
    *(.bss .bss.*)
  }

  . = ALIGN(0x1000);
  PROVIDE(KERNEL_DATA = .);

  .user : {
    .user.init = .; /* 用户程序*/
    *(.user.init);
    . = ALIGN(0x1000);
  }

  PROVIDE(USER_END = 0x80000000 + 128M);
}

